            new() { Id = 3, Name = "Physics", Abbreviation = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Abbreviation = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Abbreviation = "HIST", Description = "Study of past events and their impact on human civilization." },
        ];

        _courses =
        [
            new() { Id = 1, DepartmentId = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Ada Lovelace", InstructorBio = "Dr. Lovelace has 15 years of teaching experience in introductory computing. She holds a Ph.D. from MIT and focuses on making programming accessible to all students.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, CourseCode = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", InstructorName = "Dr. Alan Turing", InstructorBio = "Dr. Turing specializes in algorithm analysis and computational complexity. He has published extensively in top-tier conferences.", IsFeatured = true },
            new() { Id = 3, DepartmentId = 1, CourseCode = "CS 310", Title = "Database Systems", Description = "Introduction to relational database design, SQL, normalization, and transaction management. Includes hands-on projects using PostgreSQL.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Edgar Codd", InstructorBio = "Dr. Codd brings 20 years of industry and academic experience in data management and distributed systems.", IsFeatured = false },
            new() { Id = 4, DepartmentId = 1, CourseCode = "CS 450", Title = "Artificial Intelligence", Description = "Survey of AI techniques including search, knowledge representation, machine learning, and natural language processing.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Grace Hopper", InstructorBio = "Dr. Hopper is an AI researcher with expertise in deep learning and NLP. She has led multiple NSF-funded research projects.", IsFeatured = true },

            new() { Id = 5, DepartmentId = 2, CourseCode = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Leonhard Euler", InstructorBio = "Dr. Euler is an award-winning mathematics professor with a passion for making calculus intuitive and engaging.", IsFeatured = true },
            new() { Id = 6, DepartmentId = 2, CourseCode = "MATH 201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications. Essential for computer science and engineering students.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Emmy Noether", InstructorBio = "Dr. Noether is a renowned algebraist whose research focuses on abstract algebra and theoretical physics connections.", IsFeatured = false },
            new() { Id = 7, DepartmentId = 2, CourseCode = "MATH 310", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:20 PM", InstructorName = "Dr. Carl Gauss", InstructorBio = "Dr. Gauss has extensive experience in applied statistics and data science, consulting for major research institutions.", IsFeatured = false },

            new() { Id = 8, DepartmentId = 3, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Thu Lab 2:00–4:00 PM", InstructorName = "Dr. Richard Feynman", InstructorBio = "Dr. Feynman is celebrated for his dynamic lectures and his ability to explain complex physics concepts in simple terms.", IsFeatured = true },
            new() { Id = 9, DepartmentId = 3, CourseCode = "PHYS 201", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:20 PM + Fri Lab 1:00–3:00 PM", InstructorName = "Dr. Marie Curie", InstructorBio = "Dr. Curie's research bridges experimental and theoretical physics. She has mentored dozens of graduate students.", IsFeatured = false },

            new() { Id = 10, DepartmentId = 4, CourseCode = "ENG 101", Title = "English Composition", Description = "Develop academic writing skills through essay composition, argumentation, and critical analysis of texts.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. Virginia Woolf", InstructorBio = "Prof. Woolf is an expert in creative nonfiction and rhetoric with over a decade of teaching composition courses.", IsFeatured = false },
            new() { Id = 11, DepartmentId = 4, CourseCode = "ENG 220", Title = "American Literature", Description = "Survey of American literary traditions from the colonial period to the present, including poetry, fiction, and drama.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", InstructorName = "Prof. Mark Twain", InstructorBio = "Prof. Twain specializes in 19th-century American literature and humor studies. He brings literature to life with engaging discussions.", IsFeatured = false },

            new() { Id = 12, DepartmentId = 5, CourseCode = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, cultural exchanges, and transformative events from prehistory through the late medieval period.", Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM", InstructorName = "Dr. Herodotus", InstructorBio = "Dr. Herodotus is a specialist in ancient civilizations with archaeological fieldwork experience across three continents.", IsFeatured = false },
            new() { Id = 13, DepartmentId = 5, CourseCode = "HIST 250", Title = "Modern European History", Description = "Political, social, and cultural developments in Europe from the Enlightenment to the present.", Credits = 3, Schedule = "Tue/Thu 3:30–4:50 PM", InstructorName = "Dr. Leopold von Ranke", InstructorBio = "Dr. von Ranke is a historian of modern Europe focusing on diplomatic history and the development of nation-states.", IsFeatured = false },
        ];
    }

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.Find(d => d.Id == id);

    public IReadOnlyList<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        IEnumerable<Course> results = _courses;

        if (departmentId.HasValue)
        {
            results = results.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            results = results.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return results.ToList();
    }

    public IReadOnlyList<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.Find(c => c.Id == id);

    public IReadOnlyList<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application, this would persist the enrollment request to a database.
    }
}

