arguments.new_str:
using UniversityCourseCatalog.Components;
using UniversityCourseCatalog.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents();
builder.Services.AddSingleton<ICatalogService, CatalogService>();

﻿@page "/"
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-4">University Course Catalog</h1>
    <p class="lead text-muted">Explore departments, browse courses, and submit your enrollment request.</p>
    <a href="/courses" class="btn btn-primary btn-lg mt-2">Browse All Courses</a>
</div>

<section class="mb-5">
