<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-4">University Course Catalog</h1>
    <p class="lead text-muted">Explore departments, browse courses, and submit your enrollment request.</p>
    <a href="/courses" class="btn btn-primary btn-lg mt-2">Browse All Courses</a>
</div>

<section class="mb-5">
    <h2 class="mb-3">Featured Courses</h2>
    <div class="row">
        @foreach (var course in featuredCourses)
        {
            var dept = CatalogService.GetDepartment(course.DepartmentId);
            <div class="col-md-6 col-lg-4 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@course.CourseCode — @course.Title</h5>
                        <span class="badge bg-secondary mb-2">@dept?.Abbreviation</span>
                        <span class="badge bg-info text-dark mb-2">@course.Credits credits</span>
                        <p class="card-text">@Truncate(course.Description, 120)</p>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

<section>
    <h2 class="mb-3">Departments</h2>
    <div class="row">
        @foreach (var dept in departments)
        {
            <div class="col-md-6 col-lg-4 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@dept.Name (@dept.Abbreviation)</h5>
                        <p class="card-text">@dept.Description</p>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="/courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">View Courses</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

@code {
    private IReadOnlyList<Course> featuredCourses = [];
    private IReadOnlyList<Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

